\[
\frac{2n+1}{3n+5}
=\frac{n\bigl(2+\frac1n\bigr)}{n\bigl(3+\frac5n\bigr)}
=\frac{2+\tfrac1n}{3+\tfrac5n}
\;\xrightarrow[n\to\infty]{}\;\frac{2}{3}.
\]

